import com.pinterest.ktlint.test.KtLintAssertThat.Companion.EOL_CHAR
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.MAX_LINE_LENGTH_MARKER
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class FunctionSignatureRuleAnnotatedExpressionTest {
    private val functionSignatureRuleAssertThat = assertThatRule { FunctionSignatureRule() }

    @Test
    fun `Given an expression body starting with an annotation then do not merge the first line of the body expression with the function signature`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                                                                                $EOL_CHAR
            private fun f(value: String): String =
                @Suppress("DEPRECATION")
                value
            """.trimIndent()

        functionSignatureRuleAssertThat(code)
            .setMaxLineLength()
            .hasNoLintViolations()
    }
}
"}

